// import logo from './logo.svg';
// import CreateQuix from './components/CreateQuiz';

// function App() {
//   return (
//     <div className="App">
//       <header className="App-header">
//         <CreateQuix />
//       </header>
//     </div>
//   );
// }

// export default App;

import "./App.css";
import { useState } from "react";

// REGISTER COMPONENT
function Register({ onNavigate }) {
  const [form, setForm] = useState({ name: "", email: "", password: "" });
  const [errors, setErrors] = useState({});
  const [showPassword, setShowPassword] = useState(false);
  const [loading, setLoading] = useState(false);
  const [success, setSuccess] = useState(false);

  const validate = () => {
    const errs = {};
    if (!form.name.trim()) errs.name = "Full name is required.";
    else if (form.name.trim().length < 2)
      errs.name = "Name must be at least 2 characters.";
    if (!form.email.trim()) errs.email = "Email is required.";
    else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(form.email))
      errs.email = "Enter a valid email address.";
    if (!form.password) errs.password = "Password is required.";
    else if (form.password.length < 6)
      errs.password = "Password must be at least 6 characters.";
    return errs;
  };

  const handleChange = (e) => {
    const { name, value } = e.target;
    setForm((prev) => ({ ...prev, [name]: value }));
    if (errors[name]) setErrors((prev) => ({ ...prev, [name]: "" }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    const errs = validate();
    if (Object.keys(errs).length) {
      setErrors(errs);
      return;
    }

    try {
      setLoading(true);

      const response = await fetch("http://localhost:5000/register", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify(form),
      });

      const data = await response.json();

      setLoading(false);

      if (data.user) {
        setSuccess(true);
      } else {
        setErrors({ email: data.error || "Registration failed" });
      }
    } catch (err) {
      setLoading(false);
      setErrors({ general: "Server error" });
    }
  };

  const strengthScore = () => {
    const p = form.password;
    if (!p) return 0;
    let s = 0;
    if (p.length >= 6) s++;
    if (p.length >= 10) s++;
    if (/[A-Z]/.test(p) && /[a-z]/.test(p)) s++;
    if (/[0-9]/.test(p) || /[^A-Za-z0-9]/.test(p)) s++;
    return s;
  };
  const score = strengthScore();
  const strengthLabels = ["", "Weak", "Fair", "Good", "Strong"];
  const strengthColors = ["", "danger", "warning", "info", "success"];

  if (success) {
    return (
      <div className="quiz-bg d-flex align-items-center justify-content-center min-vh-100 p-3">
        <div
          className="quiz-card card border-0 shadow-lg text-center p-5"
          style={{ maxWidth: 440, width: "100%" }}
        >
          <div className="success-icon mb-3">🎉</div>
          <h2 className="fw-bold mb-2" style={{ color: "#1a1a2e" }}>
            You're all set!
          </h2>
          <p className="text-muted mb-4">
            Account created for <strong>{form.name}</strong>.<br />
            Ready to test your knowledge?
          </p>
          <button
            className="btn quiz-btn-primary w-100 py-2"
            onClick={() => onNavigate("login")}
          >
            Go to Login →
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="quiz-bg d-flex align-items-center justify-content-center min-vh-100 p-3">
      <div
        className="quiz-card card border-0 shadow-lg"
        style={{ maxWidth: 440, width: "100%" }}
      >
        <div className="quiz-card-header text-center p-4 pb-3">
          <span className="brand-icon mb-2">🧠</span>
          <h1 className="h4 fw-bold mb-1 text-white">Join QuizMaster</h1>
          <p className="text-white-50 small mb-0">
            Create your account &amp; start playing
          </p>
        </div>

        <div className="card-body p-4">
          <div className="d-flex justify-content-center gap-3 mb-4">
            {[
              ["🏆", "500+ Quizzes"],
              ["⚡", "Live Battles"],
              ["🎖️", "Leaderboards"],
            ].map(([icon, label]) => (
              <div key={label} className="quiz-badge text-center px-2 py-2">
                <div style={{ fontSize: 16 }}>{icon}</div>
                <div
                  style={{ fontSize: 10, color: "#6b7280", fontWeight: 700 }}
                >
                  {label}
                </div>
              </div>
            ))}
          </div>

          <form onSubmit={handleSubmit} noValidate>
            {/* Full Name */}
            <div className="mb-3">
              <label
                className="form-label fw-bold small"
                style={{ color: "#374151" }}
              >
                Full Name
              </label>
              <div className="input-group">
                <span className="input-group-text quiz-input-icon">👤</span>
                <input
                  type="text"
                  name="name"
                  value={form.name}
                  onChange={handleChange}
                  autoComplete="name"
                  className={`form-control quiz-input ${errors.name ? "is-invalid" : form.name ? "is-valid" : ""}`}
                  placeholder="Alex Johnson"
                />
                {errors.name && (
                  <div className="invalid-feedback">{errors.name}</div>
                )}
              </div>
            </div>

            {/* Email */}
            <div className="mb-3">
              <label
                className="form-label fw-bold small"
                style={{ color: "#374151" }}
              >
                Email Address
              </label>
              <div className="input-group">
                <span className="input-group-text quiz-input-icon">✉️</span>
                <input
                  type="email"
                  name="email"
                  value={form.email}
                  onChange={handleChange}
                  autoComplete="email"
                  className={`form-control quiz-input ${errors.email ? "is-invalid" : form.email && /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(form.email) ? "is-valid" : ""}`}
                  placeholder="alex@example.com"
                />
                {errors.email && (
                  <div className="invalid-feedback">{errors.email}</div>
                )}
              </div>
            </div>

            {/* Password */}
            <div className="mb-3">
              <label
                className="form-label fw-bold small"
                style={{ color: "#374151" }}
              >
                Password
              </label>
              <div className="input-group">
                <span className="input-group-text quiz-input-icon">🔑</span>
                <input
                  type={showPassword ? "text" : "password"}
                  name="password"
                  value={form.password}
                  onChange={handleChange}
                  autoComplete="new-password"
                  className={`form-control quiz-input ${errors.password ? "is-invalid" : ""}`}
                  placeholder="Min. 6 characters"
                />
                <button
                  type="button"
                  className="input-group-text quiz-input-icon quiz-eye-btn"
                  onClick={() => setShowPassword((v) => !v)}
                  tabIndex={-1}
                >
                  {showPassword ? "🙈" : "👁️"}
                </button>
                {errors.password && (
                  <div className="invalid-feedback">{errors.password}</div>
                )}
              </div>

              {/* Strength meter */}
              {form.password && (
                <div className="mt-2">
                  <div className="d-flex gap-1 mb-1">
                    {[1, 2, 3, 4].map((i) => (
                      <div
                        key={i}
                        className={`quiz-strength-bar ${i <= score ? `bg-${strengthColors[score]}` : "bg-light border"}`}
                      />
                    ))}
                  </div>
                  <span
                    className={`small fw-bold text-${strengthColors[score]}`}
                  >
                    {strengthLabels[score]}
                  </span>
                </div>
              )}
            </div>

            <button
              type="submit"
              className="btn quiz-btn-primary w-100 py-2 mt-1"
              disabled={loading}
            >
              {loading ? (
                <>
                  <span className="spinner-border spinner-border-sm me-2" />
                  Creating Account…
                </>
              ) : (
                "🚀 Create Account"
              )}
            </button>
          </form>

          <hr className="my-3" style={{ borderColor: "#f0f0f0" }} />
          <p className="text-center small mb-0" style={{ color: "#6b7280" }}>
            Already have an account?{" "}
            <button
              className="btn btn-link p-0 quiz-link"
              onClick={() => onNavigate("login")}
            >
              Sign In
            </button>
          </p>
        </div>
      </div>
    </div>
  );
}

// ═══════════════════════════════════════════════════════════
// LOGIN COMPONENT
// ═══════════════════════════════════════════════════════════
function Login({ onNavigate, onLoginSuccess }) {
  const [form, setForm] = useState({ email: "", password: "" });
  const [errors, setErrors] = useState({});
  const [showPassword, setShowPassword] = useState(false);
  const [loading, setLoading] = useState(false);
  const [forgotSent, setForgotSent] = useState(false);

  const validate = () => {
    const errs = {};
    if (!form.email.trim()) errs.email = "Email is required.";
    else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(form.email))
      errs.email = "Enter a valid email address.";
    if (!form.password) errs.password = "Password is required.";
    return errs;
  };

  const handleChange = (e) => {
    const { name, value } = e.target;
    setForm((prev) => ({ ...prev, [name]: value }));
    if (errors[name]) setErrors((prev) => ({ ...prev, [name]: "" }));
    if (errors.general) setErrors((prev) => ({ ...prev, general: "" }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    const errs = validate();
    if (Object.keys(errs).length) {
      setErrors(errs);
      return;
    }

    try {
      setLoading(true);

      const response = await fetch("http://localhost:5000/login", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify(form),
      });

      const data = await response.json();

      setLoading(false);

      if (data.user) {
        localStorage.setItem("user", JSON.stringify(data.user));
        onLoginSuccess(data.user);
      } else {
        setErrors({ general: "Invalid credentials" });
      }
    } catch (err) {
      setLoading(false);
      setErrors({ general: "Server error" });
    }
  };

  const handleForgot = () => {
    if (!form.email || !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(form.email)) {
      setErrors({
        email: "Enter your email above first, then click Forgot Password.",
      });
      return;
    }
    setForgotSent(true);
    setTimeout(() => setForgotSent(false), 4000);
  };

  return (
    <div className="quiz-bg d-flex align-items-center justify-content-center min-vh-100 p-3">
      <div
        className="quiz-card card border-0 shadow-lg"
        style={{ maxWidth: 420, width: "100%" }}
      >
        <div className="quiz-card-header text-center p-4 pb-3">
          <span className="brand-icon mb-2">🎯</span>
          <h1 className="h4 fw-bold mb-1 text-white">Welcome Back!</h1>
          <p className="text-white-50 small mb-0">
            Sign in to continue your quiz journey
          </p>
        </div>

        <div className="card-body p-4">
          <div className="quiz-motivate-banner d-flex align-items-center gap-2 rounded-3 px-3 py-2 mb-4">
            <span style={{ fontSize: 20 }}>🔥</span>
            <span className="small fw-bold" style={{ color: "#92400e" }}>
              You've got quizzes waiting for you!
            </span>
          </div>

          {errors.general && (
            <div
              className="alert quiz-alert-error d-flex align-items-center gap-2 py-2 mb-3 small"
              role="alert"
            >
              <span>❌</span> {errors.general}
            </div>
          )}
          {forgotSent && (
            <div
              className="alert quiz-alert-success d-flex align-items-center gap-2 py-2 mb-3 small"
              role="alert"
            >
              <span>📧</span> Reset link sent to{" "}
              <strong className="ms-1">{form.email}</strong>
            </div>
          )}

          <form onSubmit={handleSubmit} noValidate>
            {/* Email */}
            <div className="mb-3">
              <label
                className="form-label fw-bold small"
                style={{ color: "#374151" }}
              >
                Email Address
              </label>
              <div className="input-group">
                <span className="input-group-text quiz-input-icon">✉️</span>
                <input
                  type="email"
                  name="email"
                  value={form.email}
                  onChange={handleChange}
                  autoComplete="email"
                  className={`form-control quiz-input ${errors.email ? "is-invalid" : ""}`}
                  placeholder="alex@example.com"
                />
                {errors.email && (
                  <div className="invalid-feedback">{errors.email}</div>
                )}
              </div>
            </div>

            {/* Password */}
            <div className="mb-2">
              <label
                className="form-label fw-bold small"
                style={{ color: "#374151" }}
              >
                Password
              </label>
              <div className="input-group">
                <span className="input-group-text quiz-input-icon">🔑</span>
                <input
                  type={showPassword ? "text" : "password"}
                  name="password"
                  value={form.password}
                  onChange={handleChange}
                  autoComplete="current-password"
                  className={`form-control quiz-input ${errors.password ? "is-invalid" : ""}`}
                  placeholder="Your password"
                />
                <button
                  type="button"
                  className="input-group-text quiz-input-icon quiz-eye-btn"
                  onClick={() => setShowPassword((v) => !v)}
                  tabIndex={-1}
                >
                  {showPassword ? "🙈" : "👁️"}
                </button>
                {errors.password && (
                  <div className="invalid-feedback">{errors.password}</div>
                )}
              </div>
            </div>

            <div className="text-end mb-4">
              <button
                type="button"
                className="btn btn-link p-0 quiz-link small"
                onClick={handleForgot}
              >
                Forgot password?
              </button>
            </div>

            <button
              type="submit"
              className="btn quiz-btn-primary w-100 py-2"
              disabled={loading}
            >
              {loading ? (
                <>
                  <span className="spinner-border spinner-border-sm me-2" />
                  Signing In…
                </>
              ) : (
                "🎮 Start Playing"
              )}
            </button>
          </form>

          <hr className="my-3" style={{ borderColor: "#f0f0f0" }} />
          <p className="text-center small mb-0" style={{ color: "#6b7280" }}>
            Don't have an account?{" "}
            <button
              className="btn btn-link p-0 quiz-link"
              onClick={() => onNavigate("register")}
            >
              Sign Up Free
            </button>
          </p>
        </div>
      </div>
    </div>
  );
}

// ═══════════════════════════════════════════════════════════
// DASHBOARD COMPONENT
// ═══════════════════════════════════════════════════════════


// ═══════════════════════════════════════════════════════════
// ROOT APP — Router
// ═══════════════════════════════════════════════════════════
export default function App() {
  const [page, setPage] = useState("register"); // "register" | "login" | "dashboard"
  const [currentUser, setCurrentUser] = useState(null);

  const handleLoginSuccess = (user) => {
    setCurrentUser(user);
    setPage("dashboard");
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setPage("login");
  };

  return (
    <>
      {/* Bootstrap 5 CDN */}
      <link
        rel="stylesheet"
        href="https://cdnjs.cloudflare.com/ajax/libs/bootstrap/5.3.2/css/bootstrap.min.css"
        integrity="sha512-b2QcS5SsA8tZodcDtGRELiGv5SaKSk1vDHDaQRda0htPYWZ6046lr3kJ5bAAQdpV2mmA/4v0wQF9MyU6/pDIAg=="
        crossOrigin="anonymous"
      />

      {page === "register" && <Register onNavigate={setPage} />}
      {page === "login" && (
        <Login onNavigate={setPage} onLoginSuccess={handleLoginSuccess} />
      )}
      {page === "dashboard" && currentUser && (
        <Dashboard user={currentUser} onLogout={handleLogout} />
      )}
    </>
  );
}
